import React, { useState, useMemo, useCallback, useRef, useEffect } from 'react';
import { 
  Truck, 
  MapPin, 
  Play, 
  RotateCcw, 
  Plus, 
  Info, 
  Navigation,
  CheckCircle2,
  Trash2,
  BarChart3
} from 'lucide-react';

/**
 * UTILITY FUNCTIONS
 */
const calculateDistance = (p1, p2) => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

const INITIAL_DEPOT = { id: 'depot', x: 50, y: 50, label: 'Central Depot' };

const App = () => {
  const [locations, setLocations] = useState([]);
  const [truckCount, setTruckCount] = useState(2);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [results, setResults] = useState(null);
  const containerRef = useRef(null);

  // Add a location by clicking on the map area
  const handleMapClick = (e) => {
    if (isOptimizing) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const newLoc = {
      id: Date.now(),
      x: Math.round(x * 10) / 10,
      y: Math.round(y * 10) / 10,
      label: `Stop #${locations.length + 1}`
    };

    setLocations([...locations, newLoc]);
    setResults(null);
  };

  const clearLocations = () => {
    setLocations([]);
    setResults(null);
  };

  /**
   * THE ALGORITHM: Multi-Vehicle Routing (VRP)
   * 1. Greedy approach to find a global TSP-like sequence
   * 2. Split the sequence among available trucks based on proximity
   */
  const optimizeRoutes = useCallback(() => {
    if (locations.length === 0) return;
    setIsOptimizing(true);

    // Artificial delay to simulate processing
    setTimeout(() => {
      let unvisited = [...locations];
      let routes = Array.from({ length: truckCount }, () => [INITIAL_DEPOT]);
      let totalDistance = 0;

      // Simple Cluster-First, Route-Second strategy
      // We assign points to the nearest truck's current "last position"
      while (unvisited.length > 0) {
        for (let i = 0; i < truckCount && unvisited.length > 0; i++) {
          let currentPos = routes[i][routes[i].length - 1];

          let closestIdx = 0;
          let minDist = calculateDistance(currentPos, unvisited[0]);

          for (let j = 1; j < unvisited.length; j++) {
            const d = calculateDistance(currentPos, unvisited[j]);
            if (d < minDist) {
              minDist = d;
              closestIdx = j;
            }
          }

          const nextStop = unvisited.splice(closestIdx, 1)[0];
          routes[i].push(nextStop);
          totalDistance += minDist;
        }
      }

      // Return all trucks to depot
      routes.forEach((route, idx) => {
        const lastStop = route[route.length - 1];
        totalDistance += calculateDistance(lastStop, INITIAL_DEPOT);
        route.push(INITIAL_DEPOT);
      });

      setResults({
        routes,
        totalDistance: Math.round(totalDistance * 10) / 10,
        avgPerTruck: Math.round((totalDistance / truckCount) * 10) / 10
      });
      setIsOptimizing(false);
    }, 800);
  }, [locations, truckCount]);

  const routeColors = [
    'stroke-blue-500', 
    'stroke-purple-500', 
    'stroke-orange-500', 
    'stroke-emerald-500', 
    'stroke-pink-500'
  ];

  const bgColors = [
    'bg-blue-500', 
    'bg-purple-500', 
    'bg-orange-500', 
    'bg-emerald-500', 
    'bg-pink-500'
  ];

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans p-4 md:p-8">
      <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Panel: Controls */}
        <div className="lg:col-span-1 space-y-6">
          <header>
            <div className="flex items-center gap-2 mb-2">
              <div className="p-2 bg-blue-600 rounded-lg text-white">
                <Navigation size={24} />
              </div>
              <h1 className="text-2xl font-bold tracking-tight">RouteMaster AI</h1>
            </div>
            <p className="text-slate-500 text-sm">
              Advanced Logistics Optimizer using Nearest-Neighbor heuristics.
            </p>
          </header>

          <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 space-y-4">
            <h2 className="text-lg font-semibold flex items-center gap-2">
              <Truck size={18} className="text-blue-600" />
              Fleet Configuration
            </h2>

            <div>
              <label className="text-sm font-medium text-slate-700 block mb-2">
                Number of Trucks: {truckCount}
              </label>
              <input 
                type="range" 
                min="1" 
                max="5" 
                value={truckCount}
                onChange={(e) => setTruckCount(parseInt(e.target.value))}
                className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
              />
              <div className="flex justify-between text-xs text-slate-400 mt-1">
                <span>1 Truck</span>
                <span>5 Trucks</span>
              </div>
            </div>

            <div className="pt-4 space-y-3">
              <button 
                onClick={optimizeRoutes}
                disabled={locations.length === 0 || isOptimizing}
                className="w-full py-3 bg-blue-600 hover:bg-blue-700 disabled:bg-slate-300 text-white rounded-xl font-semibold flex items-center justify-center gap-2 transition-all shadow-md shadow-blue-100"
              >
                {isOptimizing ? (
                  <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent" />
                ) : (
                  <><Play size={18} /> Calculate Best Route</>
                )}
              </button>

              <button 
                onClick={clearLocations}
                className="w-full py-3 bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 rounded-xl font-semibold flex items-center justify-center gap-2 transition-all"
              >
                <RotateCcw size={18} /> Reset Map
              </button>
            </div>
          </section>

          {/* Analytics Card */}
          {results && (
            <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <h2 className="text-lg font-semibold flex items-center gap-2 mb-4">
                <BarChart3 size={18} className="text-blue-600" />
                Efficiency Report
              </h2>
              <div className="grid grid-cols-2 gap-4">
                <div className="p-3 bg-slate-50 rounded-xl">
                  <p className="text-xs text-slate-500 uppercase font-bold">Total Dist.</p>
                  <p className="text-xl font-bold text-slate-800">{results.totalDistance} km</p>
                </div>
                <div className="p-3 bg-slate-50 rounded-xl">
                  <p className="text-xs text-slate-500 uppercase font-bold">Avg / Truck</p>
                  <p className="text-xl font-bold text-slate-800">{results.avgPerTruck} km</p>
                </div>
              </div>

              <div className="mt-4 space-y-2">
                {results.routes.map((route, idx) => (
                  <div key={idx} className="flex items-center justify-between text-sm py-1 border-b border-slate-50 last:border-0">
                    <span className="flex items-center gap-2">
                      <div className={`w-3 h-3 rounded-full ${bgColors[idx]}`} />
                      Truck {idx + 1}
                    </span>
                    <span className="font-medium">{route.length - 2} Stops</span>
                  </div>
                ))}
              </div>
            </section>
          )}

          <div className="p-4 bg-blue-50 border border-blue-100 rounded-xl flex gap-3 text-blue-800 text-xs">
            <Info size={24} className="shrink-0" />
            <p>
              <strong>How to use:</strong> Click anywhere on the map to add delivery stops. The algorithm will automatically split the workload among your trucks to minimize the total travel distance.
            </p>
          </div>
        </div>

        {/* Right Panel: Map Visualization */}
        <div className="lg:col-span-2 flex flex-col gap-4">
          <div 
            ref={containerRef}
            onClick={handleMapClick}
            className={`relative flex-grow min-h-[500px] bg-white rounded-[2rem] border-4 border-white shadow-xl overflow-hidden cursor-crosshair transition-all ${isOptimizing ? 'opacity-80' : ''}`}
            style={{ backgroundImage: 'radial-gradient(#e2e8f0 1px, transparent 1px)', backgroundSize: '24px 24px' }}
          >
            {/* Legend Overlay */}
            <div className="absolute top-6 left-6 z-10 bg-white/90 backdrop-blur shadow-sm border border-slate-100 px-4 py-2 rounded-full flex gap-4 text-xs font-medium">
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full bg-red-500" /> Depot
              </div>
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full bg-emerald-500" /> Stop
              </div>
              <div className="flex items-center gap-2">
                <span className="text-slate-400">Points: {locations.length}</span>
              </div>
            </div>

            <svg className="absolute inset-0 w-full h-full pointer-events-none">
              {/* Draw Connections */}
              {results && results.routes.map((route, routeIdx) => (
                <g key={`route-${routeIdx}`}>
                  {route.map((loc, i) => {
                    if (i === 0) return null;
                    const prev = route[i - 1];
                    return (
                      <line 
                        key={`line-${routeIdx}-${i}`}
                        x1={`${prev.x}%`} y1={`${prev.y}%`}
                        x2={`${loc.x}%`} y2={`${loc.y}%`}
                        className={`${routeColors[routeIdx]} stroke-[3] opacity-60`}
                        strokeLinecap="round"
                        strokeDasharray={loc.id === 'depot' || prev.id === 'depot' ? "4 4" : "0"}
                      />
                    );
                  })}
                </g>
              ))}

              {/* Draw Depot */}
              <circle 
                cx={`${INITIAL_DEPOT.x}%`} 
                cy={`${INITIAL_DEPOT.y}%`} 
                r="10" 
                className="fill-red-500 shadow-lg"
              />
              <text 
                x={`${INITIAL_DEPOT.x}%`} 
                y={`${INITIAL_DEPOT.y - 3}%`} 
                textAnchor="middle" 
                className="text-[10px] font-bold fill-red-700 uppercase"
              >
                DEPOT
              </text>

              {/* Draw Stops */}
              {locations.map((loc) => (
                <g key={loc.id}>
                  <circle 
                    cx={`${loc.x}%`} 
                    cy={`${loc.y}%`} 
                    r="6" 
                    className="fill-emerald-500 stroke-white stroke-2 shadow-sm"
                  />
                </g>
              ))}
            </svg>

            {/* Empty State Prompt */}
            {locations.length === 0 && !isOptimizing && (
              <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <div className="text-center p-8 bg-white/50 backdrop-blur-sm rounded-3xl">
                  <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-400">
                    <Plus size={32} />
                  </div>
                  <h3 className="text-lg font-medium text-slate-600">Click the map to add stops</h3>
                  <p className="text-slate-400 text-sm">Add at least 3 points to see optimization in action</p>
                </div>
              </div>
            )}
          </div>

          {/* Location List (Mobile scrollable) */}
          <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
            {locations.map((loc, idx) => (
              <div key={loc.id} className="shrink-0 bg-white px-3 py-2 rounded-lg border border-slate-200 flex items-center gap-2 text-xs">
                <MapPin size={12} className="text-emerald-500" />
                <span className="font-medium">Stop {idx + 1}</span>
                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    setLocations(locations.filter(l => l.id !== loc.id));
                  }}
                  className="text-slate-300 hover:text-red-500 transition-colors"
                >
                  <Trash2 size={12} />
                </button>
              </div>
            ))}
          </div>
        </div>

      </div>
    </div>
  );
};

export default App;
